```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;
    // Initialize the Hexi reader with the input buffer
    hexi::Reader reader(buffer);

    // 1. Read the packet_id
    reader.read(packet.packet_id);

    // 2. Read the username using the length prefix
    // 'hexi::prefixed' tells the reader to read the length first, then the string data
    reader.read(packet.username, hexi::prefixed);

    // 3. Read the score count, then use read_container to read the scores vector
    uint32_t score_count = 0;
    reader.read(score_count);
    // read_container populates the vector with 'score_count' elements
    reader.read_container(packet.scores, score_count);

    // 4. Read the metadata string as null-terminated
    // 'hexi::null_terminated' reads until a \0 character is found
    reader.read(packet.metadata, hexi::null_terminated);

    // 5. Skip any remaining padding bytes (if any)
    if (reader.remaining() > 0) {
        reader.skip(reader.remaining());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;
    hexi::Reader reader(buffer);

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    // Request a span of 1 uint32_t. This avoids copying the bytes.
    auto id_view = reader.span<uint32_t>(1);
    if (!id_view.empty()) {
        info.packet_id = id_view[0];
    }

    // 2. Read username using prefixed adaptor to get a string_view
    // This reads the length prefix, then constructs a string_view pointing 
    // directly into the 'buffer' memory without copying the characters.
    reader.read(info.username, hexi::prefixed);

    // 3. Skip the scores vector without reading its elements
    uint32_t score_count = 0;
    reader.read(score_count); // Read the count

    // Calculate size of data to skip: count * sizeof(uint32_t)
    reader.skip(score_count * sizeof(uint32_t));

    return info;
}
