std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Ensure we don't read more than what is available in the source
    size_t actual_bytes = std::min(bytes_to_read, source_buffer.size());

    // Prepare the destination buffer
    std::vector<uint8_t> destination(actual_bytes);

