    // Read data from the adaptor into the destination vector
    adaptor.read(destination.data(), actual_bytes);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure the destination buffer is large enough to hold the source data
    if (dest_buffer.size() < source_data.size()) {
