#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // The read pointer corresponds to the start of the data in the vector.
    return buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // The write pointer corresponds to the end of the current data,
    // where new data would be appended.
    // Note: Writing to this pointer is only safe if there is available capacity.
    return buffer.data() + buffer.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;
    // Readable size is the amount of data currently in the buffer.
    info.readable_size = buffer.size();
    // Free space is the remaining capacity before a reallocation would occur.
    info.free_space = buffer.capacity() - buffer.size();
    return info;
}
