DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Basic validation: Ensure buffer has at least enough bytes for the header
    // Header = data_type (1 byte) + item_count (4 bytes)
    if (buffer.size() < sizeof(uint8_t) + sizeof(uint32_t)) {
        return result;
    }

    // 1. Create the buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Preview the first byte (data_type) using the adaptor without advancing
    // We peek at offset 0 to determine the type before creating the stream logic
    uint8_t type_preview = adaptor.peek<uint8_t>();

    // 3. Initialize the binary stream for sequential reading
    hexi::binary_stream stream(adaptor);

    // 4. Read the complete data

    // Read data_type (this advances the stream pointer past the byte we previewed)
    result.data_type = stream.read<uint8_t>();

    // Read the number of items
    uint32_t item_count = stream.read<uint32_t>();

    // Calculate required size for the items
    size_t item_size = (result.data_type == 0) ? sizeof(uint32_t) : sizeof(float);

