This implementation defines a simple data structure to allocate, then performs a sequence of allocations and deallocations. By observing the addresses returned, we can verify the LIFO (Last-In, First-Out) behavior of the internal free list managed by the private `push()` and `pop()` methods.

```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// A simple struct to be managed by the allocator
struct Payload {
    uint64_t id;
    double value;
};

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator for the Payload type with a fixed capacity
    hexi::block_allocator<Payload, element_count> allocator;

    std::cout << "--- Demonstrating Internal Free List (LIFO) Behavior ---" << std::endl;

    // 1. Allocate two blocks.
    // Internally, allocate() calls pop() to remove the head of the free list.
    Payload* ptr1 = allocator.allocate();
    ptr1->id = 1;
    std::cout << "1. Allocated ptr1 at address: " << ptr1 << std::endl;

    Payload* ptr2 = allocator.allocate();
    ptr2->id = 2;
    std::cout << "2. Allocated ptr2 at address: " << ptr2 << std::endl;

    // 2. Deallocate the blocks.
    // Internally, deallocate() calls push() to add the block to the HEAD of the free list.

    // We deallocate ptr1 first.
    // Free List State: ptr1 -> [rest of unallocated blocks]
    allocator.deallocate(ptr1);
    std::cout << "3. Deallocated ptr1 (internally pushed to free list head)" << std::endl;

    // We deallocate ptr2 second.
    // Free List State: ptr2 -> ptr1 -> [rest of unallocated blocks]
    allocator.deallocate(ptr2);
    std::cout << "4. Deallocated ptr2 (internally pushed to free list head)" << std::endl;

    // 3. Re-allocate to observe order.
    // Since the allocator uses a stack-based free list (LIFO), the last item pushed (ptr2)
    // should be the first item popped.

    Payload* ptr3 = allocator.allocate();
    std::cout << "5. Allocated ptr3 at address: " << ptr3 << std::endl;

    // Verification
    if (ptr3 == ptr2) {
        std::cout << "   -> SUCCESS: ptr3 matches ptr2. The allocator popped the most recently pushed block." << std::endl;
    } else {
        std::cout << "   -> DIFFERENT: The allocator is not using LIFO logic." << std::endl;
    }

    Payload* ptr4 = allocator.allocate();
    std::cout << "6. Allocated ptr4 at address: " << ptr4 << std::endl;

    if (ptr4 == ptr1) {
        std::cout << "   -> SUCCESS: ptr4 matches ptr1." << std::endl;
    }
}

int main() {
    demonstrate_block_allocator_behavior();
    return 0;
}
```

