```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // Required for std::min
#include <cstring>   // Required for std::memcpy

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // 1. Get the actual amount of readable data currently in the buffer
    size_t available_size = storage.readable_size();

    // 2. Determine the actual size to copy (cannot preview more than what is available)
    size_t copy_size = std::min(available_size, bytes_to_preview);

    // 3. Allocate the vector
    std::vector<uint8_t> result(copy_size);

    // 4. Copy the data if there is anything to copy
    if (copy_size > 0) {
        // storage.read_ptr() returns the pointer to the current read position
        // accessing this pointer does not advance the internal read offset
        const uint8_t* src = storage.read_ptr();
        std::memcpy(result.data(), src, copy_size);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get the number of bytes waiting to be read
    status.readable_size = storage.readable_size();

    // Get the number of bytes available for writing (capacity - used)
    status.free_space = storage.writable_size();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset the read and write pointers/offsets to the beginning of the buffer
    storage.reset();
}
