#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Initialize the Hexi FileBuffer with the provided file path
    hexi::FileBuffer file(file_path);

    // Determine the actual number of bytes to read.
    // We must ensure we do not attempt to read more than the file's total size.
    size_t file_size = file.size();
    size_t bytes_to_read = std::min(header_size, file_size);

    // Prepare the destination vector
    std::vector<uint8_t> header_data(bytes_to_read);

    // Use the peek method to copy data into the buffer without advancing the read pointer.
    // This allows subsequent operations on 'file' (if it were passed out or reused) 
    // to start reading from the beginning.
    if (bytes_to_read > 0) {
        file.peek(header_data.data(), bytes_to_read);
    }

    return header_data;
}
