template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    for (const auto& byte_val : data) {
        // Convert uint8_t to std::byte and push into the buffer.
        // Note: Depending on the specific Hexi implementation, you might want to check 
        // if the buffer is full (buffer.full()) before pushing to avoid overwriting or errors.
        buffer.push_back(static_cast<std::byte>(byte_val));
    }
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    std::vector<uint8_t> result;
    result.reserve(bytes_to_read); // Reserve memory to avoid reallocations

    for (size_t i = 0; i < bytes_to_read; ++i) {
        // Always check if the buffer has data before reading
        if (buffer.empty()) {
            break;
        }

        // Read the front element, cast it back to uint8_t, and add to result
        result.push_back(static_cast<uint8_t>(buffer.front()));

        // Remove the element from the buffer
        buffer.pop_front();
    }

    return result;
}

