    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // We invoke the serialise method passing the writer.
    // Since 'data' is const but the serialise method is not marked const,
    // we use const_cast. This is safe here as the writer will not modify 'data'.
    const_cast<UserData&>(data).serialise(writer);
}

