Since the specific API documentation for `Hexi` is not provided, this implementation follows the standard C++ binary stream serialization pattern: writing the length of the string (prefix) as a fixed-size integer (usually `uint32_t`), followed by the raw bytes of the string.

```cpp
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>
#include <cstdint> // Required for uint32_t

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // 1. Get the length of the string.
    // We use uint32_t to ensure the size is consistent across platforms (32 vs 64 bit).
    uint32_t len = static_cast<uint32_t>(str.size());

    // 2. Write the length prefix.
    writer.write(len);

    // 3. Write the string content if it is not empty.
    if (len > 0) {
        writer.write(str.data(), len);
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // 1. Read the length prefix.
    uint32_t len = 0;
    reader.read(len);

    std::string str;

    // 2. If the string has content, resize the buffer and read the data.
    if (len > 0) {
        str.resize(len);
        // &str[0] provides a mutable pointer to the string's internal buffer.
        reader.read(&str[0], len);
    }

    return str;
}
