#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // 1. Write the number of elements (count)
    // We cast to a fixed-width integer (uint32_t) to ensure binary compatibility
    auto size = static_cast<uint32_t>(container.size());
    writer.write(size);

    // 2. Write the elements
    for (const auto& element : container) {
        writer.write(element);
    }
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // 1. Read the count
    uint32_t size = 0;
    reader.read(size);

    // 2. Prepare the container
    std::vector<uint32_t> container;
    // Reserve memory to prevent multiple reallocations
    container.resize(size);

    // 3. Read the elements
    for (uint32_t i = 0; i < size; ++i) {
        reader.read(container[i]);
    }

    return container;
}
