The implementation assumes standard `buffer_adaptor` API usage where `write` and `read` accept a pointer and a size, and the buffer provides methods to query its current size and remaining capacity.

```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstddef> // For std::byte

void write_data_to_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t value, const void* data, std::size_t length) {
    // Write the uint32_t value to the buffer
    // We pass the address of the value and its size
    buffer.write(&value, sizeof(value));

    // Write the byte array to the buffer
    // We cast the void* to const std::byte* to match the vector type
    buffer.write(static_cast<const std::byte*>(data), length);
}

void read_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t& value, void* data, std::size_t length) {
    // Read the uint32_t value from the buffer
    // The order of reading must match the order of writing
    buffer.read(&value, sizeof(value));

    // Read the byte array from the buffer
    buffer.read(static_cast<std::byte*>(data), length);
}

struct BufferInfo {
    std::size_t size;
    std::size_t free_space;
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info;

    // Get the current number of bytes stored in the buffer
    info.size = buffer.size();

    // Get the remaining available space in the buffer
    info.free_space = buffer.free_space();

    return info;
}
