#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstddef> // Required for std::byte

/**
 * Skips a specified number of bytes in the buffer.
 * 
 * @param buffer The buffer adaptor instance.
 * @param bytes The number of bytes to skip.
 */
void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    // Assuming the buffer adaptor provides a 'consume' method to advance the read position
    // without copying data.
    buffer.consume(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

/**
 * Reads a MessageHeader from the buffer and then skips the subsequent body data.
 * 
 * @param buffer The buffer adaptor instance.
 * @return The read MessageHeader.
 */
MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header{};

    // Read the header bytes into the struct.
    // We reinterpret_cast to std::byte* because the underlying vector holds std::byte.
    buffer.read(reinterpret_cast<std::byte*>(&header), sizeof(MessageHeader));

    // Skip the body payload based on the length defined in the header.
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
