/**
 * Checks if the buffer adaptor supports write seeking.
 * 
 * @param buffer The buffer adaptor to check.
 * @return true if write seeking is supported, false otherwise.
 */
bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    return buffer.can_write_seek();
}

/**
 * Seeks the write position in the buffer.
 * 
 * @param buffer The buffer adaptor.
 * @param direction The seek direction (begin, current, end).
 * @param offset The offset to seek to relative to the direction.
 */
void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    if (check_can_write_seek(buffer)) {
        buffer.write_seek(offset, direction);
    }
}

/**
 * Writes a header placeholder, writes a body, and then seeks back to update the header.
 * 
 * @param buffer The buffer adaptor.
 * @param header_value The actual value to write into the header position after the body is written.
 */
void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    if (!check_can_write_seek(buffer)) {
        return;
    }

    // 1. Save the current write position (start of the header)
    // We assume write_position() returns the absolute offset from the beginning.
    auto header_pos = buffer.write_position();

    // 2. Write a placeholder for the header (e.g., 0)
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(placeholder));

    // 3. Write the body (simulated here with dummy data)
    // In a real scenario, this might be a serialized object or payload
    std::vector<std::byte> body_data = { std::byte{0xDE}, std::byte{0xAD}, std::byte{0xBE}, std::byte{0xEF} };
    buffer.write(body_data.data(), body_data.size());

    // 4. Save the position at the end of the body
    auto end_of_body_pos = buffer.write_position();

    // 5. Seek back to the header position (Absolute seek from beginning)
    buffer.write_seek(header_pos, hexi::buffer_seek::begin);

    // 6. Update the header with the actual value
    buffer.write(&header_value, sizeof(header_value));

    // 7. Seek back to the end of the body so subsequent writes continue correctly
    buffer.write_seek(end_of_body_pos, hexi::buffer_seek::begin);
}

