```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits> // Required for std::make_unsigned

using namespace hexi::detail;

/**
 * Encodes an integer value using Base-128 Varint encoding.
 * 
 * @param writer The binary stream writer to write to.
 * @param value The integer value to encode.
 * @return The number of bytes written.
 */
template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Treat the input as unsigned for bitwise operations to handle signed integers correctly
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT v = static_cast<UnsignedT>(value);
    std::size_t bytes_written = 0;

    // While the value is larger than what fits in 7 bits (>= 128)
    while (v >= 0x80) {
        // Write the lower 7 bits of the value, setting the MSB (0x80) to 1
        // to indicate that more bytes follow.
        writer.write(static_cast<uint8_t>((v & 0x7F) | 0x80));
        v >>= 7;
        bytes_written++;
    }

    // Write the final byte (MSB is 0, indicating end of varint)
    writer.write(static_cast<uint8_t>(v));
    bytes_written++;

    return bytes_written;
}

/**
 * Decodes a Varint-encoded integer from a stream.
 * 
 * @param reader The binary stream reader to read from.
 * @return The decoded integer value.
 */
template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT result = 0;
    int shift = 0;

    while (true) {
        uint8_t byte;
        reader.read(byte);

        // Extract the lower 7 bits and shift them into position
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;

        // If the MSB is 0, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;

        // Safety check: prevent infinite loops or overflow if stream is corrupted
        if (shift >= sizeof(T) * 8 + 7) {
            break; 
        }
    }

    return static_cast<T>(result);
}

/**
 * Verifies the correctness of the encoding and decoding logic.
 * 
 * @param original_value The value to test.
 * @return True if the decoded value matches the original value, false otherwise.
 */
template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // 1. Prepare a buffer
    std::vector<uint8_t> buffer;

    // 2. Encode
    {
        hexi::pmc::buffer_adaptor adaptor(buffer);
        hexi::pmc::binary_stream_writer writer(adaptor);
        encode_varint(writer, original_value);
    } // writer/adaptor scope ends, ensuring buffer is flushed/ready

    // 3. Decode
    T decoded_value = 0;
    {
        hexi::pmc::buffer_adaptor adaptor(buffer);
        hexi::pmc::binary_stream_reader reader(adaptor);
        decoded_value = decode_varint<T>(reader);
    }

    // 4. Compare
    return original_value == decoded_value;
}
```

