    // between potentially unrelated memory addresses.
    auto src_start = reinterpret_cast<std::uintptr_t>(src);
    auto src_end = src_start + src_len;

    auto dst_start = reinterpret_cast<std::uintptr_t>(dst);
    auto dst_end = dst_start + dst_len;

    // Two regions overlap if the start of one is strictly less than the end of the other
    // AND the start of the other is strictly less than the end of the first.
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Check for overlap first using the source and destination pointers with the copy length
    if (check_regions_overlap(source, length, destination, length)) {
        // Overlap detected: it is unsafe to use memcpy (or the operation is forbidden)
        return false;
