```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // 1. Create a raw buffer with enough space to hold the input
    std::vector<uint8_t> raw_buffer(input_data.size());

    // 2. Initialize the write adaptor
    hexi::pmc::buffer_write_adaptor writer(raw_buffer);

    // 3. Check available space using free()
    if (writer.free() >= input_data.size()) {
        // 4. Write data to the buffer using write()
        writer.write(input_data.data(), input_data.size());
    }

    // 5. Initialize the read adaptor with the populated buffer
    hexi::pmc::buffer_read_adaptor reader(raw_buffer);

    // 6. Check the readable size using size()
    std::size_t readable_size = reader.size();
    std::vector<uint8_t> output_data(readable_size);

    // 7. Read the data back using read()
    if (readable_size > 0) {
        reader.read(output_data.data(), readable_size);
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // 1. Initialize the read adaptor
    hexi::pmc::buffer_read_adaptor reader(buffer_data);

    // Ensure we don't peek more than available
    if (peek_size > reader.size()) {
        peek_size = reader.size();
    }

    std::vector<uint8_t> peeked_data(peek_size);

    // 2. Use read_ptr() to get a pointer to the current read position
    // (This is often used for zero-copy inspection, here we just access it as requested)
    const void* current_ptr = reader.read_ptr();
    (void)current_ptr; // Suppress unused variable warning

    // 3. Use copy() to peek at data without advancing the read cursor
    reader.copy(peeked_data.data(), peek_size);

    // 4. Use read() to actually consume the data (advancing the cursor)
    // We read into a temporary buffer or the same buffer just to advance the internal pointer
    std::vector<uint8_t> consumed_buffer(peek_size);
    reader.read(consumed_buffer.data(), peek_size);

    return peeked_data;
}
