#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cassert>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Initialize the adaptor with the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header = {0, 0};

    // Ensure buffer is large enough to hold the header
    if (buffer.size() < sizeof(Header)) {
        return header;
    }

    // 1. Use copy() to peek at header without advancing read cursor
    // This copies data into 'header' but keeps the internal cursor at the start
    adaptor.copy(&header, sizeof(Header));

    // 2. Use read_ptr() to get pointer to current position
    const uint8_t* current_ptr = adaptor.read_ptr();

    // 3. Verify the data without advancing read cursor
    // We verify that the read pointer is still at the beginning of the buffer
    assert(current_ptr == buffer.data());

    // We can also verify that the data at the read pointer matches the data we peeked
    // (Assuming little-endian architecture for direct casting comparison)
    const Header* ptr_header = reinterpret_cast<const Header*>(current_ptr);
    assert(ptr_header->magic == header.magic);
    assert(ptr_header->version == header.version);

    return header;
}

